// MainActivity.java
package com.bankingapp;

import android.app.Activity;
import android.os.Bundle;
import android.view.View;
import android.widget.Button;
import android.widget.EditText;
import android.widget.TextView;
import android.widget.Toast;
import android.content.SharedPreferences;
import java.text.SimpleDateFormat;
import java.util.Date;
import java.util.Locale;

public class MainActivity extends Activity {
    private EditText etUsername;
    private EditText etPassword;
    private EditText etAmount;
    private EditText etRecipient;
    private TextView tvBalance;
    private TextView tvTransactionHistory;
    private Button btnLogin;
    private Button btnTransfer;
    private Button btnCheckBalance;
    
    private SharedPreferences prefs;
    private static final String PREFS_NAME = "BankingPrefs";
    private String currentUser;
    
    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_main);
        
        prefs = getSharedPreferences(PREFS_NAME, MODE_PRIVATE);
        initializeViews();
        setupListeners();
    }
    
    private void initializeViews() {
        etUsername = findViewById(R.id.etUsername);
        etPassword = findViewById(R.id.etPassword);
        etAmount = findViewById(R.id.etAmount);
        etRecipient = findViewById(R.id.etRecipient);
        tvBalance = findViewById(R.id.tvBalance);
        tvTransactionHistory = findViewById(R.id.tvTransactionHistory);
        btnLogin = findViewById(R.id.btnLogin);
        btnTransfer = findViewById(R.id.btnTransfer);
        btnCheckBalance = findViewById(R.id.btnCheckBalance);
    }
    
    private void setupListeners() {
        btnLogin.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                handleLogin();
            }
        });
        
        btnTransfer.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                handleTransfer();
            }
        });
        
        btnCheckBalance.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                displayBalance();
            }
        });
    }
    
    private void handleLogin() {
        String username = etUsername.getText().toString();
        String password = etPassword.getText().toString();
        
        String storedPassword = prefs.getString(username + "_password", null);
        
        if (storedPassword == null) {
            SharedPreferences.Editor editor = prefs.edit();
            editor.putString(username + "_password", password);
            editor.putFloat(username + "_balance", 10000.00f);
            editor.putString(username + "_history", "");
            editor.apply();
            currentUser = username;
            Toast.makeText(this, "Account created successfully!", Toast.LENGTH_SHORT).show();
        } else if (storedPassword.equals(password)) {
            currentUser = username;
            Toast.makeText(this, "Login successful!", Toast.LENGTH_SHORT).show();
            displayBalance();
        } else {
            Toast.makeText(this, "Invalid credentials", Toast.LENGTH_SHORT).show();
        }
    }
    
    private void handleTransfer() {
        if (currentUser == null) {
            Toast.makeText(this, "Please login first", Toast.LENGTH_SHORT).show();
            return;
        }
        
        String amountStr = etAmount.getText().toString();
        String recipient = etRecipient.getText().toString();
        
        if (amountStr.isEmpty() || recipient.isEmpty()) {
            Toast.makeText(this, "Please fill all fields", Toast.LENGTH_SHORT).show();
            return;
        }
        
        float amount = Float.parseFloat(amountStr);
        float currentBalance = prefs.getFloat(currentUser + "_balance", 0);
        
        if (amount > currentBalance) {
            Toast.makeText(this, "Insufficient funds", Toast.LENGTH_SHORT).show();
            return;
        }
        
        SharedPreferences.Editor editor = prefs.edit();
        float newBalance = currentBalance - amount;
        editor.putFloat(currentUser + "_balance", newBalance);
        
        String timestamp = new SimpleDateFormat("yyyy-MM-dd HH:mm:ss", Locale.getDefault()).format(new Date());
        String transactionRecord = timestamp + " - Transfer to " + recipient + ": $" + amount + "\n";
        String history = prefs.getString(currentUser + "_history", "");
        editor.putString(currentUser + "_history", history + transactionRecord);
        editor.apply();
        
        Toast.makeText(this, "Transfer successful!", Toast.LENGTH_SHORT).show();
        displayBalance();
        displayTransactionHistory();
    }
    
    private void displayBalance() {
        if (currentUser == null) {
            Toast.makeText(this, "Please login first", Toast.LENGTH_SHORT).show();
            return;
        }
        
        float balance = prefs.getFloat(currentUser + "_balance", 0);
        tvBalance.setText("Current Balance: $" + String.format("%.2f", balance));
    }
    
    private void displayTransactionHistory() {
        if (currentUser == null) {
            return;
        }
        
        String history = prefs.getString(currentUser + "_history", "No transactions yet");
        tvTransactionHistory.setText("Transaction History:\n" + history);
    }
}